import { successResponse, outputAndExit, errorResponse } from '@/cli/output';
import { addUserOrigin } from '@/shared/user-origins';

import { resolveOrigin } from '../lib/resolve-origin';
import { addOriginSkill } from '@/shared/skills/origin';

import type { Command } from '@/types';
import type { DiscoverResourcesInput } from '@/operations/discover';

const SURFACE = 'cli:add-skill';

export const addSkillCommand: Command<DiscoverResourcesInput> = async input => {
  const resolved = await resolveOrigin(SURFACE, input);
  if (!resolved.ok) return outputAndExit(resolved.error, input);

  const { origin } = resolved;
  addUserOrigin(origin);

  const skillResult = await addOriginSkill(origin, SURFACE);

  if (!skillResult.isOk()) {
    return outputAndExit(
      errorResponse({
        code: 'GENERAL_ERROR',
        message: skillResult.error.message,
        surface: SURFACE,
        cause: 'skill_install_failed',
      }),
      input
    );
  }

  return outputAndExit(
    successResponse({
      ...origin,
      installed: skillResult.value.path,
      linkedAgents: skillResult.value.agents,
      note: 'Restart your MCP server for this origin to appear in the model context.',
    }),
    input
  );
};
